pub trait ImportResolver {
    fn resolve_package(&self, package_spec: &PackageSpec) -> Result<ResolvedPackage, Box<dyn std::error::Error>>;
    fn resolve_pipeline(&self, package_spec: &PackageSpec, pipeline_name: &str) -> Result<PipelineSignature, Box<dyn std::error::Error>>;
}

pub struct PackageSpec {
    pub registry: Identifier,
    pub path: Identifier,
    pub version: Version,
    pub span: Span,
}

